mutation a {
  wrapper(
    wrapper: {
      model: INNER_CUSTOMER
      cacheKey: "2c0c7698-465f-4fbb-a8c1-9614f7ec6c05"
      customerCustomerEdge: [
        {
       innerCustomer: {
