                transactionKey: "{{TransactionKey1}}"
                productType: CREDIT_CARD
                customerKey: "{{CustomerKey1}}"
                customerBankingRelationshipKey: "{{CustomerBankingRelationshipKey1}}"
              }
            ]
          }
